from flask import Flask, request, jsonify
from flask_jwt_extended import jwt_required, get_jwt_identity

app = Flask(__name__)

# Mock database
users_db = {
    "user1": {
        "email": "user1@example.com",
        "username": "user1",
        "account_type": "basic",
        "credits": 100,
        "referral_code": "REF123",
        "verified_status": False
    }
}

@app.route('/update_profile', methods=['PATCH'])
@jwt_required()
def update_profile():
    current_user = get_jwt_identity()
    user_data = users_db.get(current_user)

    if not user_data:
        return jsonify({"msg": "User not found"}), 404

    data = request.json
    fields_to_update = ['email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status']

    for field in fields_to_update:
        if field in data:
            user_data[field] = data[field]

    return jsonify({"msg": "Profile updated successfully", "user": user_data}), 200

if __name__ == '__main__':
    app.run(debug=True)